const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

interface QuoteStep {
  op: "quote";
  items: { type: string }[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

const quotePremium = (step: QuoteStep): number => {
  let premium = 0;
  for (const item of step.items) {
    const base = BASE_PREMIUMS[item.type];
    premium += base * (1 + FIRST_INSURANCE_SURCHARGE);
  }
  return premium + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
};

