const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

interface QuoteStep {
  op: "quote";
  items: { type: string }[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

const COMPONENT_BASE_PREMIUM = 25;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_BASE_PREMIUM,
  moonstone: COMPONENT_BASE_PREMIUM,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const formsBlock = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const typeBasePremium = (type: string, count: number): number => {
  if (formsBlock(type, count)) return BLOCK_PREMIUM;
  return count * BASE_PREMIUMS[type];
};

const policyBasePremium = (items: { type: string }[]): number => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return [...counts].reduce(
    (base, [type, count]) => base + typeBasePremium(type, count),
    0,
  );
};

// Premiums round up (in the MHPCO's favor); toFixed guards against
// floating-point error nudging an exact value over an integer boundary.
const roundUpPremium = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

const quotePremium = (step: QuoteStep): number => {
  const base = policyBasePremium(step.items);
  const total = base * (1 + FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
  return roundUpPremium(total);
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
};

