const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const LOYALTY_THRESHOLD = 2;
const LOYALTY_DISCOUNT = 0.2;

interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

const COMPONENT_BASE_PREMIUM = 25;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_BASE_PREMIUM,
  moonstone: COMPONENT_BASE_PREMIUM,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const formsBlock = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const typeBasePremium = (type: string, count: number): number => {
  if (formsBlock(type, count)) return BLOCK_PREMIUM;
  return count * BASE_PREMIUMS[type];
};

const policyBasePremium = (items: Item[]): number => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return [...counts].reduce(
    (base, [type, count]) => base + typeBasePremium(type, count),
    0,
  );
};

const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
  {
    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
    rate: HIGH_ENCHANTMENT_SURCHARGE,
  },
];

const itemSurchargeRate = (item: Item): number =>
  SURCHARGE_RULES.reduce(
    (rate, rule) => (rule.applies(item) ? rate + rule.rate : rate),
    0,
  );

const itemSurcharge = (item: Item): number =>
  itemSurchargeRate(item) * BASE_PREMIUMS[item.type];

const itemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurcharge(item), 0);

// Policy-wide modifiers each apply a signed rate to the policy base:
// positive rates are surcharges, negative rates are discounts.
const POLICY_MODIFIER_RULES: {
  applies: (customer: Customer) => boolean;
  rate: number;
}[] = [
  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
  {
    applies: (customer) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
    rate: -LOYALTY_DISCOUNT,
  },
];

const policyModifierRate = (customer: Customer): number =>
  POLICY_MODIFIER_RULES.reduce(
    (rate, rule) => (rule.applies(customer) ? rate + rule.rate : rate),
    0,
  );

// Premiums round up (in the MHPCO's favor); toFixed guards against
// floating-point error nudging an exact value over an integer boundary.
const roundUpPremium = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

const quotePremium = (step: QuoteStep, customer: Customer): number => {
  const { items } = step;
  const policyBase = policyBasePremium(items);
  const total =
    policyBase +
    itemSurcharges(items) +
    policyBase * policyModifierRate(customer) +
    PROCESSING_FEE;
  return roundUpPremium(total);
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  return {
    results: scenario.steps.map((step) => ({
      premium: quotePremium(step, scenario.customer),
    })),
  };
};

