import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Edge case: empty item list ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (base + 5 G fee, first insurance +10%) ---
  // Note: a single first item carries first-insurance surcharge; tests use customer history to isolate.
  it("single sword (base 100 G) → premium 115 G (100 + 10 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet (base 60 G) → premium 71 G (60 + 6 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single staff (base 80 G) → premium 93 G (80 + 8 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single potion (base 40 G) → premium 49 G (40 + 4 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // --- Components and building blocks ---
  it("2 runes (base 50 G, no block) → premium 60 G (50 + 5 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes (block, base 60 G) → premium 71 G (60 + 6 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes (no block, base 100 G) → premium 115 G (100 + 10 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes (no block, base 175 G) → premium 198 G (175 × 1.1 + 5 = 197.5, rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 198 });
  });

  // --- "Alike" components ---
  it("2 runes + 1 moonstone (no block, base 75 G) → premium 88 G (75 × 1.1 + 5 = 87.5, up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones (two blocks, base 120 G) → premium 137 G (120 × 1.1 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // --- Premium modifiers in isolation ---
  it("cursed sword (newcomer) → premium 165 G (100 base + 50 curse + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it("high-enchantment sword (ench 5, newcomer) → premium 145 G (100 + 30 ench + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 145 });
  });
  it("long-standing customer (2 yrs), sword → premium 95 G (100 − 20 loyalty + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 95 });
  });
  it("first insurance on a two-sword first contract → premium 225 G (200 + 20 first ins + 5 fee)", () => {
    const sword = { type: "sword", material: "steel", enchantment: 3, cursed: false };
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [sword, sword] }],
    });
    expect(result.results[0]).toEqual({ premium: 225 });
  });
  it("follow-up contract gets 15 % discount → step 0 = 115 G, step 1 = 100 G", () => {
    const sword = { type: "sword", material: "steel", enchantment: 3, cursed: false };
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [sword] },
        { op: "quote", items: [sword] },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
    expect(result.results[1]).toEqual({ premium: 100 });
  });
  it("processing fee applies even with no items, long-standing customer → premium 5 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 5 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → 210 G before fee (surcharge on cursed item's base only)");
  it.todo("item modifiers apply per item; policy modifiers apply to policy base; fee added last");

  // --- Modifier thresholds ---
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with exactly enchantment 5 and cursed → both surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // --- Rounding in the MHPCO's favor ---
  it.todo("premium 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout 350.5 G → final payout 350 G (rounded down)");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword, damage 500 G → payout 400 G (full minus 100 G deductible)");
  it.todo("rune damage 200 G → payout 100 G (no special clause; minus deductible)");

  // --- Enchantment threshold vs dragon material ---
  it.todo("dragon sword, enchantment 8, damage 1000 G → payout 400 G (50 % then deductible)");
  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (both clauses; 50 % wins)");
  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50 % then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword 500 G and amulet 300 G → payout 600 G (deductible per item)");

  // --- Multiple items of the same type ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages on two-sword policy → each treated as separate damage with own deductible");
  it.todo("more damages of a type than insured (two sword damages, one sword) → claim rejected (nonzero exit)");

  // --- Cap exhaustion ---
  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
  it.todo("two successive 1500 G claims on 1000 G sword → payouts 1400 G then 600 G, cap remaining 600 then 0");

  // --- Edge cases: errors ---
  it.todo("quote with unknown item type (broomstick) → nonzero exit, error on stderr, no results on stdout");
  it.todo("claim references item not in policy (amulet when only sword insured) → nonzero exit, error on stderr");
  it.todo("claim with negative damage amount (-200) → nonzero exit, error on stderr");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (enchantment 3) → premium 165 G");
  it.todo("long-standing customer's second contract, cursed sword enchantment 7 → premium 160 G");

  // --- CLI / scenario plumbing ---
  it.todo("results array has same length and order as input steps");
});

