const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

interface Policy {
  remainingCap: number;
}

const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;

const settleClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
  const requested = step.incident.damages.reduce(
    (sum, damage) => sum + damagePayout(damage),
    0,
  );
  const payout = Math.min(requested, policy.remainingCap);
