109	// A rate rule contributes its rate to a subject only when it applies.
110	interface RateRule<T> {
111	  applies: (subject: T) => boolean;
112	  rate: number;
113	}
114	
115	const sumApplicableRates = <T>(rules: RateRule<T>[], subject: T): number =>
116	  rules.reduce(
117	    (rate, rule) => (rule.applies(subject) ? rate + rule.rate : rate),
118	    0,
119	  );
