125	const SURCHARGE_RULES: RateRule<Item>[] = [
126	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
127	  {
128	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
129	    rate: HIGH_ENCHANTMENT_SURCHARGE,
130	  },
131	];
132	
133	const itemSurcharge = (item: Item): number =>
134	  sumApplicableRates(SURCHARGE_RULES, item) * BASE_PREMIUMS[item.type];
135	
136	const itemSurcharges = (items: Item[]): number =>
137	  sumOf(items, itemSurcharge);
