144	// Policy-wide modifiers each apply a signed rate to the policy base:
145	// positive rates are surcharges, negative rates are discounts.
146	const POLICY_MODIFIER_RULES: RateRule<PolicyContext>[] = [
147	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
148	  {
149	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
150	    rate: -LOYALTY_DISCOUNT,
151	  },
152	  { applies: ({ isFollowUp }) => isFollowUp, rate: -FOLLOWUP_DISCOUNT },
153	];
154	
155	const policyModifierRate = (context: PolicyContext): number =>
156	  sumApplicableRates(POLICY_MODIFIER_RULES, context);
157	
158	// A signed modifier rate scales a base: positive rates surcharge, negative discount.
159	const applyModifierRate = (base: number, rate: number): number =>
160	  base * (1 + rate);
